const input = $json;

// === Chat ID allowlist — only process messages from known chats ===
const ALLOWED_CHATS = new Set([
  '{{TELEGRAM_ADMIN_CHAT_ID}}',    // Mark King DM
  '-5143272909',   // Meshwork Team Meeting
  '-5037701631',   // Meshwork Engineering
  '-5179310269',   // Meshwork Marketing
  '-5115168416',   // Meshwork Sales
  '-5292536301',   // Meshwork Notifications
  '-5264647197',   // WMS PM
  '-5250787808',   // EstateOS
]);

const incomingChatId = String(
  input.callback_query?.message?.chat?.id ||
  input.message?.chat?.id ||
  input.chat?.id || ''
);
if (!ALLOWED_CHATS.has(incomingChatId)) {
  return [{ json: { route: 'skip' } }];
}

const staticData = $getWorkflowStaticData('global');
staticData.pendingMeetings = staticData.pendingMeetings || {};
staticData.activeMeetings = staticData.activeMeetings || {};

const agentMap = { 'pm': 'product-manager', 'planner': 'engineer-planner', 'implementer': 'engineer-implementer', 'reviewer': 'engineer-reviewer', 'architect': 'architect-jets', 'security': 'security-agent', 'qa': 'qa-agent', 'ux': 'ux-agent', 'ba': 'ba-agent', 'marketing': 'marketing', 'sales': 'sales-development', 'tom': 'ask-tom-agent' };

const meetingKeyboard = JSON.stringify({ inline_keyboard: [
  [{ text: '\ud83c\udfd7 Engineering', callback_data: 'meeting:team:engineering' }, { text: '\ud83d\udccb Product', callback_data: 'meeting:team:product' }],
  [{ text: '\ud83c\udfdb Architecture', callback_data: 'meeting:team:architecture' }, { text: '\ud83d\udc54 Leadership', callback_data: 'meeting:team:leadership' }],
  [{ text: '\ud83d\udc65 Full Team', callback_data: 'meeting:team:fullteam' }],
  [{ text: '\u2500\u2500\u2500 Individual Agents \u2500\u2500\u2500', callback_data: 'noop' }],
  [{ text: '\ud83d\udcca PM', callback_data: 'meeting:agent:pm' }, { text: '\ud83d\udee0 Planner', callback_data: 'meeting:agent:planner' }, { text: '\ud83d\udcbb Impl', callback_data: 'meeting:agent:implementer' }],
  [{ text: '\ud83d\udd0d Reviewer', callback_data: 'meeting:agent:reviewer' }, { text: '\ud83c\udfdb Architect', callback_data: 'meeting:agent:architect' }, { text: '\ud83d\udd12 Security', callback_data: 'meeting:agent:security' }],
  [{ text: '\u2705 QA', callback_data: 'meeting:agent:qa' }, { text: '\ud83c\udfa8 UX', callback_data: 'meeting:agent:ux' }, { text: '\ud83d\udcdd BA', callback_data: 'meeting:agent:ba' }],
  [{ text: '\ud83d\udce3 Marketing', callback_data: 'meeting:agent:marketing' }, { text: '\ud83d\udcb0 Sales', callback_data: 'meeting:agent:sales' }, { text: '\ud83e\udde0 Tom', callback_data: 'meeting:agent:tom' }]
]});

const presets = {
  'engineering': { agents: ['engineer-planner', 'engineer-implementer', 'engineer-reviewer'], name: 'Engineering Team' },
  'product': { agents: ['product-manager', 'ba-agent', 'ux-agent'], name: 'Product Team' },
  'architecture': { agents: ['architect-jets', 'engineer-planner', 'security-agent'], name: 'Architecture Review' },
  'leadership': { agents: ['product-manager', 'engineer-planner', 'architect-jets', 'sales-development'], name: 'Leadership Sync' },
  'fullteam': { agents: ['product-manager', 'engineer-planner', 'architect-jets', 'engineer-implementer', 'engineer-reviewer', 'security-agent', 'qa-agent'], name: 'Full Team' }
};

// Channel-to-agent mapping for conversational groups
const CHANNEL_AGENTS = { '-5037701631': 'engineer-planner', '-5179310269': 'marketing', '-5115168416': 'sales-development', '-5264647197': 'product-manager', '-5250787808': 'product-manager' };
const CHANNEL_PRODUCTS = { '-5264647197': '/projects/warranty-management', '-5250787808': '/projects/estateos' };

// === Handle callback_query (button press) ===
const cb = input.callback_query;
if (cb) {
  const chatId = String(cb.message?.chat?.id || '');
  const fromName = cb.from?.first_name || cb.from?.username || 'Unknown';
  const callbackId = cb.id;
  const data = cb.data || '';

  if (data === 'noop') {
    return [{ json: { route: 'reply', chatId, text: ' ', callbackId } }];
  }

  if (data.startsWith('meeting:team:')) {
    const preset = data.split(':')[2];
    const p = presets[preset] || presets['engineering'];
    staticData.pendingMeetings[chatId] = { agents: p.agents, fromName };
    const agentNames = p.agents.map(a => a.replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase())).join(', ');
    const forceReply = JSON.stringify({ force_reply: true, selective: true, input_field_placeholder: 'Enter meeting topic...' });
    return [{ json: { route: 'reply', chatId, text: `*${p.name}*\nAgents: ${agentNames}\n\nReply with the topic for discussion:`, keyboard: forceReply, callbackId } }];
  }

  if (data.startsWith('email:')) {
    const parts = data.split(':');
    const agent = parts[1];
    const cbKey = parts[2] || '';
    if (agent === 'ignore') {
      return [{ json: { route: 'reply', chatId, text: '\u274c Email ignored.', callbackId } }];
    }
    // Dispatch email to agent via runner — emails are Meshwork product by default
    return [{ json: { route: 'email-dispatch', agent, cbKey, chatId, callbackId, fromName } }];
  }

  if (data.startsWith('meeting:agent:')) {
    const agentKey = data.split(':')[2];
    const agent = agentMap[agentKey] || agentKey;
    const agentName = agent.replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
    staticData.pendingMeetings[chatId] = { agents: [agent], fromName };
    const forceReply = JSON.stringify({ force_reply: true, selective: true, input_field_placeholder: 'Enter meeting topic...' });
    return [{ json: { route: 'reply', chatId, text: `*${agentName}*\n\nReply with the topic for discussion:`, keyboard: forceReply, callbackId } }];
  }

  return [{ json: { route: 'skip' } }];
}

// === Handle regular messages ===
const msg = input.message || input;
const chat = msg.chat || {};
const from = msg.from || {};
const text = (msg.text || '').trim();
if (!text) return [{ json: { route: 'skip' } }];
const chatId = String(chat.id);
const fromName = from.first_name || from.username || 'Unknown';
const messageId = String(msg.message_id);
const isGroup = chat.type === 'group' || chat.type === 'supergroup';

// Check for pending meeting topic
const pending = staticData.pendingMeetings[chatId];
if (pending && !text.startsWith('/')) {
  delete staticData.pendingMeetings[chatId];
  staticData.activeMeetings[chatId] = true;
  return [{ json: { route: 'meeting-start', topic: text, agents: pending.agents, chatId, fromName: pending.fromName || fromName, workingDir: CHANNEL_PRODUCTS[chatId] || null } }];
}

// /meeting command
if (text.startsWith('/meeting')) {
  const parts = text.split(/\s+/);
  const sub = parts[1] || '';
  if (sub === 'end') { delete staticData.activeMeetings[chatId]; return [{ json: { route: 'meeting-end', chatId, fromName } }]; }
  return [{ json: { route: 'reply', chatId, text: '*Start a Team Meeting*\n\nAgents discuss autonomously for 3 rounds, then deliver structured outcomes with decisions, action items, and risks.\n\nYou can send messages during to steer the discussion.\n\nChoose a team:', keyboard: meetingKeyboard } }];
}

// Group messages
if (isGroup && !text.startsWith('/')) {
  if (staticData.activeMeetings[chatId]) {
    let tgtAgent = null;
    const atM = text.match(/^@(\w+)/);
    if (atM) { const n = atM[1].toLowerCase(); tgtAgent = agentMap[n] || n; }
    return [{ json: { route: 'meeting-message', text: text.replace(/^@\w+\s*/, ''), targetAgent: tgtAgent, chatId, fromName, messageId } }];
  }
  const channelAgent = CHANNEL_AGENTS[chatId];
  if (channelAgent) {
    const atMatch = text.match(/^@(\w+)/);
    let agent = channelAgent, userText = text;
    if (atMatch) { const n = atMatch[1].toLowerCase(); agent = agentMap[n] || channelAgent; userText = text.replace(/^@\w+\s*/, ''); }
    return [{ json: { route: 'chat', agent, conversationId: 'telegram:' + agent + ':' + chatId, workingDir: CHANNEL_PRODUCTS[chatId] || null, telegram: { chatId, messageId, user: fromName, text: userText } } }];
  }
  let targetAgent = null;
  const atMatch = text.match(/^@(\w+)/);
  if (atMatch) { const n = atMatch[1].toLowerCase(); targetAgent = agentMap[n] || n; }
  return [{ json: { route: 'meeting-message', text: text.replace(/^@\w+\s*/, ''), targetAgent, chatId, fromName, messageId } }];
}

// Standard commands
let agent = 'product-manager'; let userText = text;
if (text.startsWith('/agent ')) { const p = text.slice(7).split(' '); agent = p[0]; userText = p.slice(1).join(' '); }
else if (text.startsWith('/ask ')) { userText = text.slice(5); }
else if (text === '/help') { return [{ json: { route: 'reply', chatId, text: '*Meshwork Bot*\n\n/ask <question> - Ask the PM agent\n/agent <name> <task> - Run any agent\n/meeting - Start a team meeting\n/status - System status\n/help - This message' } }]; }
else if (text === '/status') { return [{ json: { route: 'reply', chatId, text: '_Checking status..._' } }]; }
else if (text.startsWith('/')) { return [{ json: { route: 'skip' } }]; }

return [{ json: { route: 'chat', agent, conversationId: 'telegram:' + agent + ':' + chatId, telegram: { chatId, messageId, user: fromName, text: userText } } }];

const d = $json;
if (!d.telegram) return [{ json: { skip: true } }];
const job = { agent: d.agent, message: d.telegram.text, conversationId: d.conversationId, workingDir: d.workingDir || undefined, callbackUrl: '{{N8N_PUBLIC_URL}}/webhook/runner/callback', telegram: { chatId: d.telegram.chatId, messageId: d.telegram.messageId, user: d.telegram.user } };
return [{ json: { job } }];

const runner = $json || {};
const telegram = $node['Build Chat Job'].json.job?.telegram || {};
const chatId = telegram.chatId;
if (!chatId) return [{ json: { skip: true } }];
// /chat is async (202) — send placeholder, actual response arrives via Runner Callback
const text = '_Thinking..._';
return [{ json: { chatId, text } }];

const result = $json;
const chatId = $node['Prep Meeting Data'].json.chatId;
let text;
if (result.ok || result.meetingId) {
  const agents = (result.agents || []).map(a => a.replace(/-/g, ' ').replace(/\b\w/g, l => l.toUpperCase())).join(', ');
  text = `*Meeting Started*\n\nTopic: _${result.topic || 'Team Meeting'}_\nAgents: ${agents}\nRounds: ${result.maxRounds || 3}\n\nAgents are now discussing. You'll see each response as it arrives.\nType /meeting end to stop early.`;
} else {
  text = 'Failed to start meeting: ' + (result.error || JSON.stringify(result));
}
return [{ json: { chatId, text } }];

const chatId = $node['Parse & Route'].json.chatId;
const message = $node['Parse & Route'].json.text;
const fromName = $node['Parse & Route'].json.fromName;
const targetAgent = $node['Parse & Route'].json.targetAgent;
const meetings = ($json.meetings || []);
const active = meetings.find(m => m.status === 'active' && m.telegram?.chatId === chatId) || meetings.find(m => m.status === 'active');
const gated = meetings.find(m => m.status === 'awaiting-approval' && m.telegram?.chatId === chatId) || meetings.find(m => m.status === 'awaiting-approval');
if (active) {
  const body = { message, from: fromName };
  if (targetAgent) body.agent = targetAgent;
  return [{ json: { skip: false, meetingId: active.meetingId, chatId, body, endpoint: 'message' } }];
}
if (gated) {
  const body = { decision: 'refine', refinement: message, decidedBy: fromName || 'Mark' };
  return [{ json: { skip: false, meetingId: gated.meetingId, chatId, body, endpoint: 'decision' } }];
}
return [{ json: { skip: true, chatId, text: 'No active meeting. Tap /meeting to start one.' } }];

const chatId = $node['Parse & Route'].json.chatId;
const meetings = ($json.meetings || []);
const active = meetings.find(m => m.status === 'active' && m.telegram?.chatId === chatId) || meetings.find(m => m.status === 'active');
if (!active) { return [{ json: { skip: true, chatId, text: 'No active meeting to end.' } }]; }
return [{ json: { skip: false, meetingId: active.meetingId, chatId } }];
